    public partial class HelpTopicSubService : BaseService<HelpTopicSub>, IHelpTopicSubService
    {
        public HelpTopicSubService(IUnitOfWork uow) : base(uow)
        {

        }

        public override async Task Validation(HelpTopicSub item, Result<HelpTopicSub> executionResult)
        {
            if (await UOW.GetRepositoryAsync<HelpTopicSub>().HasRecordsAsync(x => x.SubTopic == item.SubTopic  && x.ID != item.ID))
            {
                executionResult.AddMessageItem(new MessageItem(nameof(HelpTopicSub.SubTopic), "SubTopics already exists"));
            }
        }
        public override async Task<HelpTopicSub> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<HelpTopicSub>().SingleAsync(
                predicate: x => x.ID == id,
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IPaginate<HelpTopicSub>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<HelpTopicSub>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.SubTopic.Contains(search.Name))
                     && x.HelpTopicId == search.RefId.Value,
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "SubTopic", ascending: !search.IsDescend);
        }
    }
